ALGORITHM EvaluateUniversal(domain, predicate)
// domain = set of elements to check
// predicate = function that returns TRUE/FALSE for each element
BEGIN
 FOR EACH element IN domain DO
 IF predicate(element) = FALSE THEN
 RETURN FALSE // Found element that fails
 END IF
 END FOR
 RETURN TRUE // All elements satisfied the predicate
END

ALGORITHM EvaluateExistential(domain, predicate)
BEGIN
 FOR EACH element IN domain DO
 IF predicate(element) = TRUE THEN
 RETURN TRUE // Found at least one satisfying element
 END IF
 END FOR
 RETURN FALSE // No element satisfied the predicate
END

// Example usage:
// Domain: {1,2,3,4,5}
// Predicate: IsPrime(x)
// EvaluateUniversal: checks if ALL elements are prime → FALSE
// EvaluateExistential: checks if ANY element is prime → TRUE (2,3,5)

ALGORITHM ModusPonens(premises, query)
// premises = list of (antecedent, consequent) pairs
// query = proposition to prove
BEGIN
 FOR EACH premise IN premises DO
 antecedent ← premise.antecedent
 consequent ← premise.consequent

 // If we know antecedent is true
 IF antecedent = TRUE OR CanProve(antecedent, premises) THEN
 // Then consequent must be true by Modus Ponens
 IF consequent = query THEN
 RETURN TRUE // Successfully derived query
 END IF
 END IF
 END FOR
 RETURN FALSE
END

// Example:
// Premises: [(Rains, Wet), (Studies, Passes)]
// Query: Wet
// Since Rains is TRUE, by Modus Ponens, Wet is TRUE
// Output: TRUE
